8	<style>
9	  :root {
10	    --bg: #0f0f23;
11	    --card: #1a1a3e;
12	    --card-border: #2a2a5e;
13	    --text: #e0e0e0;
14	    --text-dim: #8888aa;
15	    --accent: #4fc3f7;
16	    --green: #4caf50;
17	    --red: #ef5350;
18	    --hold: #9e9e9e;
19	    --font: system-ui, -apple-system, sans-serif;
20	    --mono: 'JetBrains Mono', 'Fira Code', monospace;
21	  }
22	  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
23	  body { background: var(--bg); color: var(--text); font-family: var(--font); line-height: 1.5; padding: 0; }
24	  a { color: var(--accent); text-decoration: none; }
25	
26	  /* Header */
27	  .header {
28	    display: flex; align-items: center; gap: 16px; padding: 12px 24px;
29	    background: #12122a; border-bottom: 1px solid var(--card-border); flex-wrap: wrap;
30	  }
31	  .header-title { font-size: 1.4rem; font-weight: 700; color: #fff; }
32	  .version-badge {
33	    font-size: 0.7rem; background: var(--accent); color: #000; padding: 2px 8px;
34	    border-radius: 10px; font-weight: 600; vertical-align: middle;
35	  }
36	  .header-spacer { flex: 1; }
37	  .instance-toggle { display: flex; gap: 0; }
38	  .instance-btn {
39	    padding: 6px 18px; border: 1px solid var(--card-border); background: var(--card);
40	    color: var(--text-dim); cursor: pointer; font-size: 0.85rem; font-family: var(--font);
41	    transition: all 0.15s;
42	  }
43	  .instance-btn:first-child { border-radius: 6px 0 0 6px; }
44	  .instance-btn:last-child { border-radius: 0 6px 6px 0; }
45	  .instance-btn.active { background: var(--accent); color: #000; font-weight: 600; border-color: var(--accent); }
46	  .ctrl-btn {
47	    padding: 6px 16px; border: 1px solid var(--card-border); border-radius: 6px;
48	    background: var(--card); color: var(--text); cursor: pointer; font-size: 0.85rem;
49	    font-family: var(--font); transition: all 0.15s;
50	  }
51	  .ctrl-btn:hover { border-color: var(--accent); }
52	  .ctrl-btn.running { border-color: var(--red); color: var(--red); }
53	  .ctrl-btn.stopped { border-color: var(--green); color: var(--green); }
54	  .status-dot {
55	    width: 10px; height: 10px; border-radius: 50%; display: inline-block;
56	  }
57	  .status-dot.running { background: var(--green); box-shadow: 0 0 6px var(--green); }
58	  .status-dot.stopped { background: var(--red); }
59	  .status-dot.halted { background: #ff9800; box-shadow: 0 0 6px #ff9800; }
60	  .status-label { font-size: 0.85rem; color: var(--text-dim); margin-left: 4px; }
61	  .market-status {
62	    font-size: 0.75rem; padding: 3px 10px; border-radius: 10px;
63	    font-weight: 600; margin-left: 8px;
64	  }
65	  .market-status.open { background: rgba(76,175,80,0.2); color: var(--green); }
66	  .market-status.closed { background: rgba(239,83,80,0.2); color: var(--red); }
67	  /* Live mode warning */
68	  body.live-mode .header { border-bottom: 2px solid var(--red); }
69	  .live-warning { display: none; font-size: 0.7rem; background: var(--red); color: #fff; padding: 2px 8px; border-radius: 10px; font-weight: 700; margin-left: 6px; }
70	  body.live-mode .live-warning { display: inline-block; }
71	  .health-badge { font-size: 0.72rem; padding: 3px 10px; border-radius: 10px; font-weight: 600; }
72	  .health-badge.ok { background: rgba(76,175,80,0.2); color: var(--green); }
73	  .health-badge.warn { background: rgba(255,152,0,0.2); color: #ff9800; }
74	  .health-badge.bad { background: rgba(239,83,80,0.2); color: var(--red); }
75	  .header-meta { display: flex; align-items: center; gap: 12px; font-size: 0.75rem; color: var(--text-dim); }
76	  .next-cycle { font-family: var(--mono); }
77	  .last-updated { font-family: var(--mono); opacity: 0.7; }
78	  .gear-btn {
79	    background: none; border: none; color: var(--text-dim); cursor: pointer;
80	    font-size: 1.3rem; padding: 4px 8px; transition: color 0.15s;
81	  }
82	  .gear-btn:hover { color: var(--accent); }
83	
84	  /* Main layout */
85	  .main { max-width: 1400px; margin: 0 auto; padding: 20px 24px; }
86	
87	  /* Cards row */
88	  .cards { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; margin-bottom: 20px; }
89	  .card {
90	    background: var(--card); border: 1px solid var(--card-border); border-radius: 10px;
91	    padding: 18px 20px;
92	  }
93	  .card-label { font-size: 0.78rem; color: var(--text-dim); text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 4px; }
94	  .card-label[data-tip] { cursor: help; border-bottom: 1px dotted var(--text-dim); }
95	  .card-sub { font-size: 0.75rem; color: var(--text-dim); font-family: var(--mono); margin-top: 2px; }
96	  .card-sub.positive { color: var(--green); }
97	  .card-sub.negative { color: var(--red); }
98	  .card-value { font-size: 1.6rem; font-weight: 700; font-family: var(--mono); }
99	  /* Margin bar */
100	  .margin-bar-track { height: 6px; background: #1e1e40; border-radius: 3px; margin-top: 6px; overflow: hidden; }
101	  .margin-bar-fill { height: 100%; border-radius: 3px; transition: width 0.3s; }
102	  /* Tooltips */
103	  [data-tip] { position: relative; }
104	  [data-tip]:hover::after {
105	    content: attr(data-tip); position: absolute; bottom: 100%; left: 50%;
106	    transform: translateX(-50%); padding: 6px 10px; background: #222244;
107	    border: 1px solid var(--card-border); border-radius: 6px; font-size: 0.72rem;
108	    color: var(--text); white-space: normal; width: max-content; max-width: 240px;
109	    z-index: 100; pointer-events: none; font-weight: 400; text-transform: none;
110	    letter-spacing: normal; line-height: 1.4; margin-bottom: 4px;
111	  }
112	  .card-value.positive { color: var(--green); }
113	  .card-value.negative { color: var(--red); }
114	
115	  /* Panels */
116	  .panel {
117	    background: var(--card); border: 1px solid var(--card-border); border-radius: 10px;
118	    padding: 18px 20px; margin-bottom: 20px;
119	  }
120	  .panel-title { font-size: 1rem; font-weight: 600; margin-bottom: 12px; color: #fff; }
121	
122	  /* Tables */
123	  .table-wrap { overflow-x: auto; }
124	  table { width: 100%; border-collapse: collapse; font-size: 0.82rem; }
125	  th { text-align: left; color: var(--text-dim); font-weight: 500; padding: 8px 10px;
126	       border-bottom: 1px solid var(--card-border); white-space: nowrap; font-size: 0.75rem;
127	       text-transform: uppercase; letter-spacing: 0.5px; }
128	  td { padding: 7px 10px; border-bottom: 1px solid #1e1e40; white-space: nowrap; font-family: var(--mono); font-size: 0.8rem; }
129	  tr:hover td { background: rgba(79, 195, 247, 0.04); }
130	  .dir-buy { color: var(--green); font-weight: 600; }
131	  .dir-sell { color: var(--red); font-weight: 600; }
132	  .dir-hold { color: var(--hold); }
133	  .scrollable-table { max-height: 340px; overflow-y: auto; }
134	
135	  /* Chart */
136	  .chart-container { position: relative; height: 280px; }
137	
138	  /* Bot log */
139	  .log-entry {
140	    border: 1px solid var(--card-border); border-radius: 8px; margin-bottom: 8px;
141	    overflow: hidden;
142	  }
143	  .log-header {
144	    display: flex; justify-content: space-between; align-items: center;
145	    padding: 10px 14px; cursor: pointer; background: rgba(255,255,255,0.02);
146	    transition: background 0.15s;
147	  }
148	  .log-header:hover { background: rgba(79, 195, 247, 0.05); }
149	  .log-cycle { font-weight: 600; font-family: var(--mono); font-size: 0.85rem; }
150	  .log-time { font-size: 0.75rem; color: var(--text-dim); }

